import React, { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

function LoginScreen() {
  const [isRegister, setIsRegister] = useState(false);
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  const navigate = useNavigate();

  const submitHandler = async (e) => {
    e.preventDefault();

    try {
      if (isRegister) {
        await axios.post("http://localhost:5000/api/users/register", {
          name,
          email,
          password,
        });

        alert("Registration Successful");
        setIsRegister(false);
      } else {
        const { data } = await axios.post(
          "http://localhost:5000/api/users/login",
          { email, password }
        );

        localStorage.setItem("userInfo", JSON.stringify(data));
        navigate("/products");
      }
    } catch (error) {
      alert(error.response?.data?.message || "Something went wrong");
    }
  };

  return (
    <div style={containerStyle}>
      <div style={logoCircle}>🛒</div>

      <h1 style={titleStyle}>Welcome to SmartCart</h1>
      <p style={subtitleStyle}>
        Sign in to continue your shopping
      </p>

      <form onSubmit={submitHandler} style={cardStyle}>
        {isRegister && (
          <>
            <label style={labelStyle}>Full Name</label>
            <input
              type="text"
              placeholder="Enter your name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              required
              style={inputStyle}
            />
          </>
        )}

        <label style={labelStyle}>Email Address</label>
        <input
          type="email"
          placeholder="name@example.com"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          required
          style={inputStyle}
        />

        <div style={{ display: "flex", justifyContent: "space-between" }}>
          <label style={labelStyle}>Password</label>
          {!isRegister && (
            <span style={forgotStyle}>Forgot?</span>
          )}
        </div>

        <input
          type="password"
          placeholder="••••••••"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          required
          style={inputStyle}
        />

        <button type="submit" style={buttonStyle}>
          {isRegister ? "Register to SmartCart →" : "Login to SmartCart →"}
        </button>
      </form>

      <p style={bottomText}>
        {isRegister ? "Already have an account?" : "New User?"}
        <span
          onClick={() => setIsRegister(!isRegister)}
          style={bottomLink}
        >
          {isRegister ? " Login now" : " Register now"}
        </span>
      </p>
    </div>
  );
}

/* ================= STYLES ================= */

const containerStyle = {
  minHeight: "100vh",
  display: "flex",
  flexDirection: "column",
  alignItems: "center",
  justifyContent: "center",
  background: "linear-gradient(135deg, #7b5cff, #ff4d8d)",
  fontFamily: "Arial, sans-serif",
  textAlign: "center",
  padding: "20px",
};

const logoCircle = {
  width: "70px",
  height: "70px",
  background: "rgba(255,255,255,0.3)",
  borderRadius: "20px",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  fontSize: "28px",
  marginBottom: "20px",
};

const titleStyle = {
  color: "#fff",
  fontSize: "36px",
  fontWeight: "bold",
  marginBottom: "10px",
};

const subtitleStyle = {
  color: "#f0f0f0",
  marginBottom: "30px",
};

const cardStyle = {
  background: "#ffffff",
  padding: "35px",
  borderRadius: "25px",
  width: "380px",
  boxShadow: "0 15px 40px rgba(0,0,0,0.2)",
  textAlign: "left",
};

const labelStyle = {
  fontWeight: "600",
  marginBottom: "5px",
  display: "block",
};

const inputStyle = {
  width: "100%",
  padding: "14px",
  marginTop: "8px",
  marginBottom: "20px",
  borderRadius: "15px",
  border: "none",
  background: "#f2f2f2",
  fontSize: "14px",
  outline: "none",
};

const forgotStyle = {
  color: "#ff4d8d",
  fontSize: "13px",
  cursor: "pointer",
};

const buttonStyle = {
  width: "100%",
  padding: "14px",
  borderRadius: "30px",
  border: "none",
  background: "#ff1e63",
  color: "#fff",
  fontWeight: "bold",
  fontSize: "15px",
  cursor: "pointer",
  marginTop: "10px",
};

const bottomText = {
  marginTop: "25px",
  color: "#fff",
  fontSize: "14px",
};

const bottomLink = {
  fontWeight: "bold",
  cursor: "pointer",
};

export default LoginScreen;
